from decimal import Decimal, ROUND_HALF_UP

lines = data.strip().splitlines()
total = Decimal('0')
count = 0
for line in lines:
    parts = line.split()
    # Expected format: date time txn id=... user=... amount=... status=...
    if len(parts) < 7:
        continue
    user = None
    amount = None
    status = None
    for part in parts:
        if part.startswith('user='):
            user = part.split('=', 1)[1]
        elif part.startswith('amount='):
            amount = part.split('=', 1)[1]
        elif part.startswith('status='):
            status = part.split('=', 1)[1]
    if user == 'u139' and status == 'ok' and amount is not None:
        try:
            total += Decimal(amount)
            count += 1
        except Exception as e:
            print('bad amount', amount, e)

answer = float(total.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP))
print(count, total, answer)
